export const getGleanQuery = (columnName, table) => `
-- Auto-generated by Glean Dictionary.
-- https://docs.telemetry.mozilla.org/cookbooks/accessing_glean_data.html#accessing-glean-data-in-bigquery

SELECT
  ${columnName}
  /* Uncomment this and the next block to segment by locale
  ,client_info.locale,
  COUNT(*) AS count
  */
FROM
  ${table} AS m
WHERE
  -- Pick yesterday's data from stable/historical tables.
  -- https://docs.telemetry.mozilla.org/cookbooks/bigquery/querying.html#table-layout-and-naming
  DATE(submission_timestamp) = DATE_SUB(CURRENT_DATE(), INTERVAL 1 DAY)
  AND ${columnName} IS NOT NULL
/* Uncomment this and the previous commented block to segment by locale
GROUP BY
  ${columnName},
  client_info.locale
  ORDER BY COUNT DESC
*/
-- IMPORTANT: Remove the limit clause when the query is ready.
LIMIT 10`;

export const getGleanQuerySTMOTemplateUrl = (columnName, table) =>
  `https://sql.telemetry.mozilla.org/queries/110672/source?p_columnName=${columnName}&p_table=${table}`;

export const getGleanLabeledCounterQuery = (columnName, table) => `
-- Auto-generated by the Glean Dictionary.
-- https://docs.telemetry.mozilla.org/cookbooks/accessing_glean_data.html#accessing-glean-data-in-bigquery

SELECT
  DATE(submission_timestamp) AS date,
  metric.key AS label,
  SUM(metric.value) AS count,
FROM
  ${table} AS m
CROSS JOIN
  UNNEST(${columnName}) AS metric
WHERE
  -- Pick yesterday's data from stable/historical tables.
  -- https://docs.telemetry.mozilla.org/cookbooks/bigquery/querying.html#table-layout-and-naming
  DATE(submission_timestamp) = DATE_SUB(CURRENT_DATE(), INTERVAL 1 DAY)
GROUP BY 1, 2
-- IMPORTANT: Remove the limit clause when the query is ready.
LIMIT 10`;

export const getGleanLabeledCounterQuerySTMOTemplateUrl = (columnName, table) =>
  `https://sql.telemetry.mozilla.org/queries/110677/source?p_columnName=${columnName}&p_table=${table}`;

export const getGleanDualLabeledCounterQuery = (columnName, table) => `
-- Auto-generated by the Glean Dictionary.
-- https://docs.telemetry.mozilla.org/cookbooks/accessing_glean_data.html#accessing-glean-data-in-bigquery

SELECT
  keys.key,
  categories.key as category,
  categories.value
FROM
  ${table} AS m
CROSS JOIN
  UNNEST(${columnName}) AS keys
CROSS JOIN
  UNNEST(keys.value) AS categories
WHERE
  -- Pick yesterday's data from stable/historical tables.
  -- https://docs.telemetry.mozilla.org/cookbooks/bigquery/querying.html#table-layout-and-naming
  DATE(submission_timestamp) = DATE_SUB(CURRENT_DATE(), INTERVAL 1 DAY)
  AND ${columnName} IS NOT NULL
-- IMPORTANT: Remove the limit clause when the query is ready.
LIMIT 10`;

